    'home.ticker':            'Brand Identity &nbsp;·&nbsp; Editorial Design &nbsp;·&nbsp; Typography &nbsp;·&nbsp; Packaging &nbsp;·&nbsp; Print &nbsp;·&nbsp; Visual Systems &nbsp;·&nbsp; &nbsp;',
